  6→package kotlinx.datetime
  7→
  8→import kotlinx.datetime.internal.*
  9→import kotlinx.datetime.format.*
 10→import kotlinx.datetime.serializers.UtcOffsetSerializer
 11→import kotlinx.serialization.Serializable
 12→import kotlin.math.abs
 13→
 14→@Serializable(with = UtcOffsetSerializer::class)
 15→public actual class UtcOffset private constructor(public actual val totalSeconds: Int) {
 16→
 17→    override fun hashCode(): Int = totalSeconds
 18→    override fun equals(other: Any?): Boolean = other is UtcOffset && this.totalSeconds == other.totalSeconds
 19→    actual override fun toString(): String = format(Formats.ISO)
 20→
 21→    public actual companion object {
 22→
 23→        public actual val ZERO: UtcOffset = UtcOffset(totalSeconds = 0)
 24→
 25→        public actual fun parse(input: CharSequence, format: DateTimeFormat<UtcOffset>): UtcOffset = format.parse(input)
 26→
 27→        @Deprecated("This overload is only kept for binary compatibility", level = DeprecationLevel.HIDDEN)
 28→        public fun parse(offsetString: String): UtcOffset = parse(input = offsetString)
 29→
 30→        private fun validateTotal(totalSeconds: Int) {
 31→            if (totalSeconds !in -18 * SECONDS_PER_HOUR .. 18 * SECONDS_PER_HOUR) {
 32→                throw IllegalArgumentException("Total seconds value is out of range: $totalSeconds")
 33→            }
 34→        }
 35→
 36→        // org.threeten.bp.ZoneOffset#validate
 37→        private fun validate(hours: Int, minutes: Int, seconds: Int) {
 38→            if (hours < -18 || hours > 18) {
 39→                throw IllegalArgumentException("Zone offset hours not in valid range: value " + hours +
 40→                        " is not in the range -18 to 18")
 41→            }
 42→            if (hours > 0) {
 43→                if (minutes < 0 || seconds < 0) {
 44→                    throw IllegalArgumentException("Zone offset minutes and seconds must be positive because hours is positive")
 45→                }
 46→            } else if (hours < 0) {
 47→                if (minutes > 0 || seconds > 0) {
 48→                    throw IllegalArgumentException("Zone offset minutes and seconds must be negative because hours is negative")
 49→                }
 50→            } else if (minutes > 0 && seconds < 0 || minutes < 0 && seconds > 0) {
 51→                throw IllegalArgumentException("Zone offset minutes and seconds must have the same sign")
 52→            }
 53→            if (abs(minutes) > 59) {
 54→                throw IllegalArgumentException("Zone offset minutes not in valid range: abs(value) " +
 55→                        abs(minutes) + " is not in the range 0 to 59")
 56→            }
 57→            if (abs(seconds) > 59) {
 58→                throw IllegalArgumentException("Zone offset seconds not in valid range: abs(value) " +
 59→                        abs(seconds) + " is not in the range 0 to 59")
 60→            }
 61→            if (abs(hours) == 18 && (abs(minutes) > 0 || abs(seconds) > 0)) {
 62→                throw IllegalArgumentException("Utc offset not in valid range: -18:00 to +18:00")
 63→            }
 64→        }
 65→
 66→        // org.threeten.bp.ZoneOffset#ofHoursMinutesSeconds
 67→        internal fun ofHoursMinutesSeconds(hours: Int, minutes: Int, seconds: Int): UtcOffset {
 68→            validate(hours, minutes, seconds)
 69→            return if (hours == 0 && minutes == 0 && seconds == 0) ZERO
 70→            else ofSeconds(hours * SECONDS_PER_HOUR + minutes * SECONDS_PER_MINUTE + seconds)
 71→        }
 72→
 73→        // org.threeten.bp.ZoneOffset#ofTotalSeconds
 74→        internal fun ofSeconds(seconds: Int): UtcOffset {
 75→            validateTotal(seconds)
