16→@Serializable(with = UtcOffsetSerializer::class)
17→public actual class UtcOffset(internal val zoneOffset: ZoneOffset) {
18→    public actual val totalSeconds: Int get() = zoneOffset.totalSeconds
19→
20→    override fun hashCode(): Int = zoneOffset.hashCode()
21→    override fun equals(other: Any?): Boolean = other is UtcOffset && this.zoneOffset == other.zoneOffset
22→    actual override fun toString(): String = zoneOffset.toString()
23→
24→    public actual companion object {
25→        public actual val ZERO: UtcOffset = UtcOffset(ZoneOffset.UTC)
26→
27→        public actual fun parse(input: CharSequence, format: DateTimeFormat<UtcOffset>): UtcOffset = when {
28→            format === Formats.ISO -> parseWithFormat(input, isoFormat)
29→            format === Formats.ISO_BASIC -> parseWithFormat(input, isoBasicFormat)
30→            format === Formats.FOUR_DIGITS -> parseWithFormat(input, fourDigitsFormat)
31→            else -> format.parse(input)
32→        }
33→
34→        @Deprecated("This overload is only kept for binary compatibility", level = DeprecationLevel.HIDDEN)
35→        public fun parse(offsetString: String): UtcOffset = parse(input = offsetString)
36→
37→        @Suppress("FunctionName")
38→        public actual fun Format(block: DateTimeFormatBuilder.WithUtcOffset.() -> Unit): DateTimeFormat<UtcOffset> =
39→            UtcOffsetFormat.build(block)
40→    }
41→
42→    public actual object Formats {
43→        public actual val ISO: DateTimeFormat<UtcOffset> get() = ISO_OFFSET
44→        public actual val ISO_BASIC: DateTimeFormat<UtcOffset> get() = ISO_OFFSET_BASIC
45→        public actual val FOUR_DIGITS: DateTimeFormat<UtcOffset> get() = FOUR_DIGIT_OFFSET
46→    }
