75→private fun parseWithFormat(input: CharSequence, format: DateTimeFormatter) = try {
76→    format.parse(input, ZoneOffset::from).let(::UtcOffset)
77→} catch (e: DateTimeException) {
78→    throw DateTimeFormatException(e)
