 36→        // org.threeten.bp.ZoneOffset#validate
 37→        private fun validate(hours: Int, minutes: Int, seconds: Int) {
 38→            if (hours < -18 || hours > 18) {
 39→                throw IllegalArgumentException("Zone offset hours not in valid range: value " + hours +
 40→                        " is not in the range -18 to 18")
 41→            }
 42→            if (hours > 0) {
 43→                if (minutes < 0 || seconds < 0) {
 44→                    throw IllegalArgumentException("Zone offset minutes and seconds must be positive because hours is positive")
 45→                }
 46→            } else if (hours < 0) {
 47→                if (minutes > 0 || seconds > 0) {
 48→                    throw IllegalArgumentException("Zone offset minutes and seconds must be negative because hours is negative")
 49→                }
 50→            } else if (minutes > 0 && seconds < 0 || minutes < 0 && seconds > 0) {
 51→                throw IllegalArgumentException("Zone offset minutes and seconds must have the same sign")
 52→            }
 53→            if (abs(minutes) > 59) {
 54→                throw IllegalArgumentException("Zone offset minutes not in valid range: abs(value) " +
 55→                        abs(minutes) + " is not in the range 0 to 59")
 56→            }
 57→            if (abs(seconds) > 59) {
 58→                throw IllegalArgumentException("Zone offset seconds not in valid range: abs(value) " +
 59→                        abs(seconds) + " is not in the range 0 to 59")
 60→            }
 61→            if (abs(hours) == 18 && (abs(minutes) > 0 || abs(seconds) > 0)) {
 62→                throw IllegalArgumentException("Utc offset not in valid range: -18:00 to +18:00")
 63→            }
 64→        }
